This is an obfuscated implementation of the **A* (A-Star) Pathfinding Algorithm** operating on a randomly generated 2D grid. 

The code uses standard obfuscation techniques like string array shifting, RC4 string encryption, and control-flow flattening (using a `switch` statement inside a `while` loop to hide the execution order).

Here is the fully deobfuscated, renamed, and cleaned-up version of the code, followed by an explanation of how it works.

### Deobfuscated Code

```javascript
const gridWidth = 20;
const gridHeight = 15;
const config = {
    penalty: 'manhattan',
    adjacentCost: 1.414, // Cost for diagonal movement
    traversalCost: 1,    // Cost for horizontal/vertical movement
    minIterations: 1000,
    clearanceRatio: 0.25 // 25% chance for a tile to be an obstacle
};

// 1. Generate the Grid
let grid = [];
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // Randomly place obstacles based on clearanceRatio (1 = obstacle, 0 = walkable)
        grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
    }
}

// Set start and end points, ensuring they are not obstacles
const originNode = { x: 0, y: 0 };
const waypointNode = { x: gridWidth - 1, y: gridHeight - 1 };
grid[originNode.y][originNode.x] = 0;
grid[waypointNode.y][waypointNode.x] = 0;

// 2. Heuristic Function: Calculates distance between two nodes
function measureProximity(node, target) {
    let dx = Math.abs(node.x - target.x);
    let dy = Math.abs(node.y - target.y);

    // Uses Manhattan distance by default
    if (config.penalty === 'manhattan') {
        return dx + dy;
    }
    // Fallback to Euclidean distance
    return Math.sqrt(dx * dx + dy * dy);
}

// 3. Neighbor Function: Gets valid surrounding tiles
function getAncestors(node) {
    let validNeighbors = [];
    let directions = [
        { dx: 0, dy: -1, cost: config.traversalCost }, // Up
        { dx: 0, dy: 1,  cost: config.traversalCost }, // Down
        { dx: -1, dy: 0, cost: config.traversalCost }, // Left
        { dx: 1, dy: 0,  cost: config.traversalCost }, // Right
        { dx: -1, dy: -1, cost: config.adjacentCost }, // Top-Left
        { dx: 1, dy: -1,  cost: config.adjacentCost }, // Top-Right
        { dx: -1, dy: 1,  cost: config.adjacentCost }, // Bottom-Left
        { dx: 1, dy: 1,   cost: config.adjacentCost }  // Bottom-Right
    ];

    for (let i = 0; i < directions.length; i++) {
        let nx = node.x + directions[i].dx;
        let ny = node.y + directions[i].dy;

        // Check if within bounds and not an obstacle
        if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
            validNeighbors.push({ x: nx, y: ny, moveCost: directions[i].cost });
        }
    }
    return validNeighbors;
}

// Helper: Creates a string ID for a node (e.g., "5,10")
function nodeKey(node) {
    return node.x + ',' + node.y;
}

// 4. Core A* Algorithm
function findRoute(start, end) {
    let openSet = {};   // Nodes to be evaluated
    let closedSet = {}; // Nodes already evaluated
    let gScores = {};   // Cost from start along best known path
    let fScores = {};   // Estimated total cost from start to goal
    let cameFrom = {};  // Used to reconstruct the final path
    let iterations = 0;

    let startKey = nodeKey(start);
    openSet[startKey] = start;
    gScores[startKey] = 0;
    fScores[startKey] = measureProximity(start, end);

    while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
        iterations++;

        // Find node in openSet with the lowest fScore
        let currentKey = null;
        let lowestFScore = Infinity;
        for (let key in openSet) {
            if (fScores[key] < lowestFScore) {
                lowestFScore = fScores[key];
                currentKey = key;
            }
        }

        let current = openSet[currentKey];

        // If we reached the destination
        if (current.x === end.x && current.y === end.y) {
            let path = [current];
            let currNodeKey = currentKey;

            // Reconstruct the path backwards
            while (cameFrom[currNodeKey]) {
                currNodeKey = cameFrom[currNodeKey];
                path.push(openSet[currNodeKey] || closedSet[currNodeKey] || {
                    x: parseInt(currNodeKey.split(',')[0]), 
                    y: parseInt(currNodeKey.split(',')[1])
                });
            }
            return { path: path, cost: gScores[currentKey], iterations: iterations };
        }

        // Move current node from openSet to closedSet
        delete openSet[currentKey];
        closedSet[currentKey] = current;

        // Check neighbors
        let neighbors = getAncestors(current);
        for (let i = 0; i < neighbors.length; i++) {
            let neighbor = neighbors[i];
            let neighborKey = nodeKey(neighbor);

            if (closedSet[neighborKey]) continue; // Ignore already evaluated nodes

            let tentativeGScore = gScores[currentKey] + neighbor.moveCost;

            // If we found a shorter path to this neighbor
            if (gScores[neighborKey] === undefined || tentativeGScore < gScores[neighborKey]) {
                cameFrom[neighborKey] = currentKey;
                gScores[neighborKey] = tentativeGScore;
                fScores[neighborKey] = tentativeGScore + measureProximity(neighbor, end);
                openSet[neighborKey] = neighbor;
            }
        }
    }

    // Path not found
    return { path: [], cost: Infinity, iterations: iterations };
}

// 5. Execution and Logging
let result = findRoute(originNode, waypointNode);
console.log('Path found:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
```

### How it Works

1. **Map Generation:** It creates a 20x15 grid (`gridHeight` x `gridWidth`). It populates the grid with randomly generated obstacles. Every tile has a 25% chance of being an obstacle (`clearanceRatio: 0.25`).
2. **Start and End Points:** It sets the starting point to the top-left `(0, 0)` and the destination to the bottom-right `(19, 14)`. It hardcodes these two specific spots to be walkable `0`.
3. **The Heuristic (`measureProximity`):** A* uses a heuristic to guess how far a node is from the end point to prioritize which paths to check first. This code uses **Manhattan Distance** (calculating distance purely using horizontal and vertical grid lines).
4. **Neighbor Checking (`getAncestors`):** The algorithm allows 8-way movement. Moving purely North, South, East, or West costs `1` (`traversalCost`). Moving diagonally costs `1.414` (the square root of 2, labeled `adjacentCost`).
5. **The A\* Loop (`findRoute`):** 
   * It maintains a dictionary of paths to explore (`openSet`) and paths it has already explored (`closedSet`).
   * It continually picks the most promising tile based on `fScore` (Distance traveled so far + Guess distance to the end).
   * It stops when it reaches the destination or hits a hard limit of `1000` iterations (to prevent infinite loops on impossible maps).
6. **Output:** Once the loop finishes, it prints out the length of the discovered path, the total numerical cost to travel it, and how many iterations the algorithm took to find it. If no path is possible because the obstacles blocked everything off, it will return an empty path and a cost of `Infinity`.
